+                if (std.mem.eql(u8, n.id_slice, e.to_slice)) to_row = n.row;
+            }
+            if (from_row != null and to_row != null and from_row.? == to_row.?) {
+                c.gviz_set_edge_attr(graph, ep, "constraint", "false");
+            }
+        }
